**Input:**

```json
db.movies.aggregate([
  {
    "$search": {
      "text": {
        "path": "title",
        "query": "shop",
        "score": {
          "function":{
            "gauss": {
              "path": {
                "value": "imdb.rating",
                "undefined": 4.6
              },
              "origin": 9.5,
              "scale": 5,
              "offset": 0,
              "decay": 0.5
            }
          }
        }
      },
      "scoreDetails": true
    }
  },
  {
    "$limit": 10
  },
  {
    "$project": {
      "_id": 0,
      "title": 1,
      "score": { "$meta": "searchScore" },
      "scoreDetails": {"$meta": "searchScoreDetails"}
    }
  }
])
```

